/*
Emitted when the dock is closed with the Close button in the context popup, before it's removed from its parent. See [Closable].

[Closable]: https://pkg.go.dev/graphics.gd/classdb/EditorDock#Instance.Closable
*/
func (self Instance) OnClosed(cb func(), flags ...Signal.Flags) Instance {
	var flags_together Signal.Flags
	for _, flag := range flags {
		flags_together |= flag
	}
	self.AsObject()[0].Connect(gd.NewStringName("closed"), gd.NewCallable(cb), int64(flags_together))
	return self
}

func (self class) Closed() Signal.Any {
	return Signal.Via(gd.SignalProxy{}, pointers.Pack(gd.NewSignalOf(self.AsObject(), gd.NewStringName(`closed`))))
}

