func (self class) Virtual(name string) reflect.Value {
	switch name {
	case "_update_layout":
		return reflect.ValueOf(self._update_layout)
	case "_save_layout_to_config":
		return reflect.ValueOf(self._save_layout_to_config)
	case "_load_layout_from_config":
		return reflect.ValueOf(self._load_layout_from_config)
	default:
		return gd.VirtualByName(MarginContainer.Advanced(self.AsMarginContainer()), name)
	}
}

